            path: 'scripts/dep-audit.sh',
            role: 'script',
            content:
                '#!/bin/sh\n# dep-audit.sh — defensive, read-only dependency audit.\n#\n# Detects dependency manifests in a project and runs the matching ecosystem audit tool\n# IF that tool is installed locally. Read-only: the SCRIPT itself sends nothing custom and\n# uploads no code. (Note: some audit tools query their OWN vulnerability databases over the\n# network — that is the tool\'s behavior, not this script\'s.)\n#\n# Output: a human-readable markdown summary plus a JSON status block describing which\n# ecosystems were found, which tools ran, and which were skipped.\n#\n# Usage: dep-audit.sh [ROOT]   (ROOT defaults to ".")\n#        dep-audit.sh -h | --help\n#\n# Never fails the whole script because a sub-tool errored or reported findings.\n\nset -eu\n\nROOT="."\nMAX_OUTPUT_LINES=200\n\nusage() {\n  cat <<\'EOF\'\ndep-audit.sh — defensive, read-only dependency audit\n\nUsage:\n  dep-audit.sh [ROOT]      Audit the project rooted at ROOT (default: ".")\n  dep-audit.sh -h|--help   Show this help\n\nFor each detected manifest, runs the matching ecosystem audit IF the tool is installed:\n  package-lock.json / package.json   -> npm audit  (pnpm/yarn audit if those lockfiles)\n  requirements.txt / pyproject.toml  -> pip-audit  (notes \'safety\' if pip-audit absent)\n  Pipfile                            -> pip-audit\n  go.mod                             -> govulncheck\n  pom.xml / build.gradle             -> OWASP dependency-check (dependency-check.sh)\n  Cargo.toml                         -> cargo audit\n  Gemfile.lock                       -> bundle audit\n\nBehavior:\n  - manifest present AND tool present  -> run it, capture output (failures tolerated)\n  - manifest present, tool MISSING     -> note \'install <tool> to audit\'\n  - no manifest                        -> skip silently\nEOF\n}\n\ncase "${1:-}" in\n  -h|--help) usage; exit 0 ;;\n  "") : ;;\n  *) ROOT="$1" ;;\nesac\n\nif [ ! -d "$ROOT" ]; then\n  echo "error: ROOT \'$ROOT\' is not a directory" >&2\n  exit 2\nfi\n\n# JSON status accumulators (built as comma-joined object fragments).\nJSON_ECO=""\nadd_json() {\n  # add_json <ecosystem> <manifest_found:true|false> <tool> <tool_present:true|false> <status>\n  frag="{\\"ecosystem\\":\\"$1\\",\\"manifest_found\\":$2,\\"tool\\":\\"$3\\",\\"tool_present\\":$4,\\"status\\":\\"$5\\"}"\n  if [ -z "$JSON_ECO" ]; then\n    JSON_ECO="$frag"\n  else\n    JSON_ECO="$JSON_ECO,$frag"\n  fi\n}\n\nhas() { command -v "$1" >/dev/null 2>&1; }\n\n# Find a manifest anywhere under ROOT (returns 0 if found). Skips vendored dirs.\nmanifest_exists() {\n  find "$ROOT" \\\n    \\( -name .git -o -name node_modules -o -name vendor -o -name target -o -name dist \\) -prune -o \\\n    -type f -name "$1" -print 2>/dev/null | head -n 1 | grep -q .\n}\n\n# Run a command, tolerate non-zero exit, truncate output.\nrun_tool() {\n  # run_tool <label> <command...>\n  label="$1"; shift\n  echo "#### $label"\n  echo \'```\'\n  # shellcheck disable=SC2068\n  ( cd "$ROOT" && $@ ) 2>&1 | head -n "$MAX_OUTPUT_LINES" || true\n  total=$( ( cd "$ROOT" && $@ ) 2>&1 | wc -l 2>/dev/null || echo 0 )\n  if [ "${total:-0}" -gt "$MAX_OUTPUT_LINES" ]; then\n    echo "... (output truncated at $MAX_OUTPUT_LINES lines; $total total)"\n  fi\n  echo \'```\'\n  echo ""\n}\n\necho "# Dependency Audit"\necho ""\necho "Root: \\`$ROOT\\`  |  Mode: read-only, local"\necho ""\necho "> Software Composition Analysis (SCA) tools may query their own vulnerability databases"\necho "> over the network. This script sends no custom data and uploads no source code."\necho ""\n\nFOUND_ANY=0\n\n# ---- Node (npm / pnpm / yarn) ----\nif manifest_exists package-lock.json || manifest_exists package.json; then\n  FOUND_ANY=1\n  echo "## Node.js"\n  if manifest_exists pnpm-lock.yaml && has pnpm; then\n    run_tool "pnpm audit --json" pnpm audit --json\n    add_json "node" true "pnpm audit" true "ran"\n  elif manifest_exists yarn.lock && has yarn; then\n    run_tool "yarn audit --json" yarn audit --json\n    add_json "node" true "yarn audit" true "ran"\n  elif has npm; then\n    run_tool "npm audit --json" npm audit --json\n    add_json "node" true "npm audit" true "ran"\n  else\n    echo "Node manifest found, npm/pnpm/yarn not installed — install one to audit."\n    echo ""\n    add_json "node" true "npm/pnpm/yarn" false "skipped_tool_missing"\n  fi\nfi\n\n# ---- Python (pip-audit / safety) ----\nif manifest_exists requirements.txt || manifest_exists pyproject.toml || manifest_exists Pipfile; then\n  FOUND_ANY=1\n  echo "## Python"\n  if has pip-audit; then\n    run_tool "pip-audit" pip-audit\n    add_json "python" true "pip-audit" true "ran"\n  elif has safety; then\n    run_tool "safety check (pip-audit not found, using safety)" safety check\n    add_json "python" true "safety" true "ran"\n  else\n    echo "Python manifest found, pip-audit not installed — install pip-audit (or safety) to audit."\n    echo ""\n    add_json "python" true "pip-audit" false "skipped_tool_missing"\n  fi\nfi\n\n# ---- Go (govulncheck) ----\nif manifest_exists go.mod; then\n  FOUND_ANY=1\n  echo "## Go"\n  if has govulncheck; then\n    run_tool "govulncheck ./..." govulncheck ./...\n    add_json "go" true "govulncheck" true "ran"\n  else\n    echo "go.mod found, govulncheck not installed — install govulncheck to audit."\n    echo ""\n    add_json "go" true "govulncheck" false "skipped_tool_missing"\n  fi\nfi\n\n# ---- Java (OWASP dependency-check) ----\nif manifest_exists pom.xml || manifest_exists build.gradle || manifest_exists build.gradle.kts; then\n  FOUND_ANY=1\n  echo "## Java / JVM"\n  if has dependency-check.sh; then\n    run_tool "OWASP dependency-check" dependency-check.sh --scan "$ROOT" --format JSON --out -\n    add_json "java" true "dependency-check" true "ran"\n  else\n    echo "JVM build file found, OWASP dependency-check (dependency-check.sh) not installed —"\n    echo "install it to audit JVM dependencies."\n    echo ""\n    add_json "java" true "dependency-check" false "skipped_tool_missing"\n  fi\nfi\n\n# ---- Rust (cargo audit) ----\nif manifest_exists Cargo.toml; then\n  FOUND_ANY=1\n  echo "## Rust"\n  if has cargo && cargo audit --version >/dev/null 2>&1; then\n    run_tool "cargo audit" cargo audit\n    add_json "rust" true "cargo audit" true "ran"\n  else\n    echo "Cargo.toml found, cargo-audit not installed — run \'cargo install cargo-audit\' to audit."\n    echo ""\n    add_json "rust" true "cargo audit" false "skipped_tool_missing"\n  fi\nfi\n\n# ---- Ruby (bundle audit) ----\nif manifest_exists Gemfile.lock; then\n  FOUND_ANY=1\n  echo "## Ruby"\n  if has bundle && bundle audit version >/dev/null 2>&1; then\n    run_tool "bundle audit check --update" bundle audit check --update\n    add_json "ruby" true "bundle audit" true "ran"\n  elif has bundle-audit; then\n    run_tool "bundle-audit check --update" bundle-audit check --update\n    add_json "ruby" true "bundle-audit" true "ran"\n  else\n    echo "Gemfile.lock found, bundler-audit not installed — install bundler-audit to audit."\n    echo ""\n    add_json "ruby" true "bundle audit" false "skipped_tool_missing"\n  fi\nfi\n\nif [ "$FOUND_ANY" -eq 0 ]; then\n  echo "## No supported dependency manifests found under \\`$ROOT\\`."\n  echo ""\nfi\n\necho "## JSON status"\necho \'```json\'\necho "{\\"root\\":\\"$ROOT\\",\\"ecosystems\\":[$JSON_ECO]}"\necho \'```\'\necho ""\necho "> Reminder: do not assert a specific CVE/version as vulnerable unless the evidence is in the"\necho "> repository or the tool above reported it. Verify with Software Composition Analysis (SCA)."\n\nexit 0\n',
            bytes: 7343,
