                '#!/bin/sh\n# secret-scan.sh — defensive, LOCAL-ONLY, read-only secret detector.\n#\n# Scans a directory for credential patterns and REDACTS every match (the raw secret is never\n# printed). Sends nothing over the network. Skips .git, node_modules, vendor, and binaries.\n#\n# Output: JSON {findings:[{file,line,type,redacted,likely_placeholder}],count} plus a human summary.\n#\n# Usage: secret-scan.sh [DIR]    (DIR defaults to ".")\n#        secret-scan.sh -h | --help\n\nset -eu\n\nDIR="."\n\nusage() {\n  cat <<\'EOF\'\nsecret-scan.sh — defensive, local-only secret detector (read-only, redacted output)\n\nUsage:\n  secret-scan.sh [DIR]      Scan DIR for credentials (default: ".")\n  secret-scan.sh -h|--help  Show this help\n\nDetects (redacted in output): AWS access keys, private key blocks, GitHub tokens, Slack tokens,\nGoogle API keys, Stripe live keys, JWTs, connection strings with user:pass@, and generic\npassword/secret/token/api_key assignments. Marks obvious example/placeholder values.\n\nNever prints raw secrets. Never sends data anywhere. Skips .git, node_modules, vendor, binaries.\nEOF\n}\n\ncase "${1:-}" in\n  -h|--help) usage; exit 0 ;;\n  "") : ;;\n  *) DIR="$1" ;;\nesac\n\nif [ ! -d "$DIR" ]; then\n  echo "error: DIR \'$DIR\' is not a directory" >&2\n  exit 2\nfi\n\nif ! command -v grep >/dev/null 2>&1; then\n  echo "error: grep not available" >&2\n  exit 3\nfi\n\n# Patterns: each line is "TYPE<TAB>REGEX". Kept defensive (detection only).\nPATTERNS=$(printf \'%s\\n\' \\\n  "aws_access_key_id\tAKIA[0-9A-Z]{16}" \\\n  "private_key_block\t-----BEGIN [A-Z ]*PRIVATE KEY-----" \\\n  "github_token\tgh[pousr]_[A-Za-z0-9]{20,}" \\\n  "github_pat\tgithub_pat_[A-Za-z0-9_]{20,}" \\\n  "slack_token\txox[baprs]-[A-Za-z0-9-]{10,}" \\\n  "google_api_key\tAIza[0-9A-Za-z_-]{35}" \\\n  "stripe_live_key\tsk_live_[0-9A-Za-z]{16,}" \\\n  "jwt\teyJ[A-Za-z0-9_-]+\\.eyJ[A-Za-z0-9_-]+\\.[A-Za-z0-9_-]+" \\\n  "connection_string\t[a-zA-Z][a-zA-Z0-9+.-]*://[^:@/[:space:]]+:[^@/[:space:]]+@" \\\n  "generic_secret_assignment\t(password|passwd|secret|token|api[_-]?key|access[_-]?key)[\\"\']?[[:space:]]*[:=][[:space:]]*[\\"\'][^\\"\']{6,}[\\"\']" \\\n)\n\n# Redact a matched line\'s sensitive token: keep first 4 + last 2 chars, mask the rest.\n# Operates on the whole matched line; collapses long alnum/secret-ish runs.\nredact_line() {\n  # read from stdin, emit a redacted single line\n  awk \'{\n    line=$0\n    out=""\n    n=length(line)\n    i=1\n    while (i<=n) {\n      # accumulate a run of secret-ish characters\n      run=""\n      while (i<=n) {\n        c=substr(line,i,1)\n        if (c ~ /[A-Za-z0-9_+\\/=.-]/) { run=run c; i++ } else { break }\n      }\n      if (length(run) >= 8) {\n        head=substr(run,1,4)\n        tail=substr(run,length(run)-1,2)\n        masked=""\n        midlen=length(run)-6\n        if (midlen<1) midlen=1\n        for (k=0;k<midlen;k++) masked=masked "*"\n        out = out head masked tail\n      } else {\n        out = out run\n      }\n      if (i<=n) { out = out substr(line,i,1); i++ }\n    }\n    print out\n  }\'\n}\n\n# Determine if a value looks like a placeholder / example.\nis_placeholder() {\n  printf \'%s\' "$1" | grep -E -i -q \\\n    \'changeme|change-me|example|dummy|placeholder|xxxx|your-.*-here|<[^>]+>|todo|sample|fake|test-only|notreal|redacted\' \\\n    && echo true || echo false\n}\n\nJSON_FINDINGS=""\nCOUNT=0\nTMP_JSON="${TMPDIR:-/tmp}/secret-scan.$$.json"\n: > "$TMP_JSON"\ntrap \'rm -f "$TMP_JSON"\' EXIT INT TERM\n\n# JSON string escaper.\njesc() {\n  printf \'%s\' "$1" | sed -e \'s/\\\\/\\\\\\\\/g\' -e \'s/"/\\\\"/g\' -e \'s/\t/\\\\t/g\'\n}\n\necho "# Secret Scan"\necho ""\necho "Dir: \\`$DIR\\`  |  Mode: local-only, read-only, redacted output"\necho ""\n\n# Iterate patterns.\nprintf \'%s\\n\' "$PATTERNS" | while IFS=\'\t\' read -r TYPE REGEX; do\n  [ -z "$TYPE" ] && continue\n  # grep recursive, line numbers, extended regex, binary-skip, prune common dirs.\n  grep -E -r -n -I \\\n    --exclude-dir=.git --exclude-dir=node_modules --exclude-dir=vendor \\\n    --exclude-dir=dist --exclude-dir=build --exclude-dir=target \\\n    "$REGEX" "$DIR" 2>/dev/null | while IFS= read -r HIT; do\n      # HIT format: file:line:content\n      FILE=$(printf \'%s\' "$HIT" | cut -d: -f1)\n      LINE=$(printf \'%s\' "$HIT" | cut -d: -f2)\n      CONTENT=$(printf \'%s\' "$HIT" | cut -d: -f3-)\n      [ -z "$LINE" ] && continue\n      REDACTED=$(printf \'%s\' "$CONTENT" | redact_line | cut -c1-200)\n      PLACEHOLDER=$(is_placeholder "$CONTENT")\n      # Emit human line.\n      echo "- \\`$FILE:$LINE\\` — **$TYPE** (placeholder: $PLACEHOLDER)"\n      echo "  - redacted: \\`$(printf \'%s\' "$REDACTED" | sed \'s/^[[:space:]]*//\')\\`"\n      # Append JSON fragment to a temp file (subshell can\'t mutate parent vars in `while | read`).\n      printf \'{"file":"%s","line":%s,"type":"%s","redacted":"%s","likely_placeholder":%s}\\n\' \\\n        "$(jesc "$FILE")" "$LINE" "$(jesc "$TYPE")" "$(jesc "$REDACTED")" "$PLACEHOLDER" \\\n        >> "$TMP_JSON"\n    done\ndone\n\nif [ -s "$TMP_JSON" ]; then\n  COUNT=$(wc -l < "$TMP_JSON" | tr -d \' \')\n  JSON_FINDINGS=$(tr \'\\n\' \',\' < "$TMP_JSON" | sed \'s/,$//\')\nelse\n  COUNT=0\n  JSON_FINDINGS=""\nfi\n\necho ""\nif [ "$COUNT" -eq 0 ]; then\n  echo "_No credential-pattern matches found (local source scan only)._"\nfi\necho ""\necho "## JSON"\necho \'```json\'\necho "{\\"findings\\":[$JSON_FINDINGS],\\"count\\":$COUNT}"\necho \'```\'\necho ""\necho "> Note: secrets may also live in git history, CI variables, or Dockerfile ARG/ENV —"\necho "> not only in tracked source. A committed secret should be rotated, not just deleted."\n\nexit 0\n',
