                '#!/bin/sh\n# grep-dangerous-sinks.sh — defensive, read-only scan for dangerous code sinks.\n#\n# Greps a repository for risky sinks (code/command execution, raw SQL, deserialization, and\n# misc risky calls) as INVESTIGATION STARTING POINTS. These are NOT confirmed vulnerabilities and\n# this script produces NO exploits — every hit must be reviewed manually to confirm the input is\n# attacker-controlled and the sink is reachable.\n#\n# Output: markdown grouped by category plus JSON {sinks:[{category,file,line,snippet}],count}.\n#\n# Usage: grep-dangerous-sinks.sh [DIR]   (DIR defaults to ".")\n#        grep-dangerous-sinks.sh -h | --help\n\nset -eu\n\nDIR="."\nMAX_PER_CATEGORY=200\n\nusage() {\n  cat <<\'EOF\'\ngrep-dangerous-sinks.sh — defensive, read-only dangerous-sink scanner\n\nUsage:\n  grep-dangerous-sinks.sh [DIR]      Scan DIR (default: ".")\n  grep-dangerous-sinks.sh -h|--help  Show this help\n\nCategories scanned (each hit is a STARTING POINT for manual review, not a confirmed vuln):\n  - Code execution       (eval/exec/new Function/instance_eval/create_function ...)\n  - Command execution    (os.system, shell=True, Runtime.exec, child_process.exec, backticks ...)\n  - Raw SQL              (string concat/format/interpolation in SQL queries)\n  - Deserialization      (pickle.loads, yaml.load, readObject, unserialize, Marshal.load ...)\n  - Misc risky           (innerHTML, dangerouslySetInnerHTML, document.write, TLS verify off,\n                          Math.random for tokens)\n\nSkips .git, node_modules, vendor, dist, build, target, and binary files. Read-only and local.\nEOF\n}\n\ncase "${1:-}" in\n  -h|--help) usage; exit 0 ;;\n  "") : ;;\n  *) DIR="$1" ;;\nesac\n\nif [ ! -d "$DIR" ]; then\n  echo "error: DIR \'$DIR\' is not a directory" >&2\n  exit 2\nfi\n\nif ! command -v grep >/dev/null 2>&1; then\n  echo "error: grep not available — cannot scan" >&2\n  exit 3\nfi\n\nTMP_JSON="${TMPDIR:-/tmp}/dangerous-sinks.$$.json"\n: > "$TMP_JSON"\ntrap \'rm -f "$TMP_JSON"\' EXIT INT TERM\n\njesc() {\n  printf \'%s\' "$1" | sed -e \'s/\\\\/\\\\\\\\/g\' -e \'s/"/\\\\"/g\' -e \'s/\t/\\\\t/g\'\n}\n\n# scan_category <category> <why> <regex>\nscan_category() {\n  CATEGORY="$1"\n  WHY="$2"\n  REGEX="$3"\n  echo "## $CATEGORY"\n  echo ""\n  echo "_Why investigate: ${WHY}_"\n  echo ""\n  HITS=$(grep -E -r -n -I \\\n    --exclude-dir=.git --exclude-dir=node_modules --exclude-dir=vendor \\\n    --exclude-dir=dist --exclude-dir=build --exclude-dir=target \\\n    "$REGEX" "$DIR" 2>/dev/null | head -n "$MAX_PER_CATEGORY" || true)\n\n  if [ -z "$HITS" ]; then\n    echo "_No matches._"\n    echo ""\n    return 0\n  fi\n\n  printf \'%s\\n\' "$HITS" | while IFS= read -r HIT; do\n    [ -z "$HIT" ] && continue\n    FILE=$(printf \'%s\' "$HIT" | cut -d: -f1)\n    LINE=$(printf \'%s\' "$HIT" | cut -d: -f2)\n    SNIPPET=$(printf \'%s\' "$HIT" | cut -d: -f3- | sed \'s/^[[:space:]]*//\' | cut -c1-200)\n    [ -z "$LINE" ] && continue\n    echo "- \\`$FILE:$LINE\\` — \\`$SNIPPET\\`"\n    printf \'{"category":"%s","file":"%s","line":%s,"snippet":"%s"}\\n\' \\\n      "$(jesc "$CATEGORY")" "$(jesc "$FILE")" "$LINE" "$(jesc "$SNIPPET")" >> "$TMP_JSON"\n  done\n  echo ""\n}\n\necho "# Dangerous Sinks (investigation starting points)"\necho ""\necho "Dir: \\`$DIR\\`  |  Mode: read-only, local"\necho ""\necho "> These are STARTING POINTS for manual review, NOT confirmed vulnerabilities. Confirm the"\necho "> input is attacker-controlled and the sink is reachable before reporting a finding."\necho ""\n\n# ---- Code execution ----\nscan_category "Code execution" \\\n  "dynamic code evaluation can run attacker-controlled input as code" \\\n  \'(\\beval\\(|\\bexec\\(|\\bcompile\\()|new[[:space:]]+Function\\(|setTimeout\\([[:space:]]*["\'\\\'\']|\\binstance_eval\\b|\\bclass_eval\\b|\\bmodule_eval\\b|\\.send\\([[:space:]]*["\'\\\'\':]|\\bassert\\([[:space:]]*\\$|create_function\\(\'\n\n# ---- Command execution ----\nscan_category "Command execution" \\\n  "spawning OS commands with concatenated input enables command injection" \\\n  \'os\\.system\\(|subprocess\\.[A-Za-z_]+\\([^)]*shell[[:space:]]*=[[:space:]]*True|os\\.popen\\(|Runtime\\.getRuntime\\(\\)\\.exec\\(|new[[:space:]]+ProcessBuilder\\(|exec\\.Command\\(["\'\\\'\']?(sh|bash|cmd)|child_process\\.(exec|execSync)\\(|\\bsystem\\(|\\bshell_exec\\(|\\bpassthru\\(|\\bpopen\\(|IO\\.popen\\(|%x\\{\'\n\n# ---- Raw SQL ----\nscan_category "Raw SQL (string building)" \\\n  "building SQL by concatenation/format/interpolation enables SQL injection" \\\n  \'(execute|query|raw|createQuery|find_by_sql)\\([^)]*("[^"]*"[[:space:]]*\\+|\\+[[:space:]]*"[^"]*"|%[[:space:]]*\\(|\\.format\\(|f"|`)|"SELECT[^"]*"[[:space:]]*\\+|fmt\\.Sprintf\\([^)]*SELECT|where\\("[^"]*#\\{\'\n\n# ---- Deserialization ----\nscan_category "Insecure deserialization" \\\n  "deserializing untrusted data into live objects enables remote code execution" \\\n  \'pickle\\.loads?\\(|yaml\\.load\\([^)]*\\)|marshal\\.loads?\\(|ObjectInputStream|readObject\\(|XMLDecoder|\\bunserialize\\(|Marshal\\.load\\(|YAML\\.load\\(|node-serialize|serialize-javascript\'\n\n# ---- Misc risky ----\nscan_category "Misc risky sinks" \\\n  "DOM HTML sinks, disabled TLS verification, and weak randomness for tokens" \\\n  \'dangerouslySetInnerHTML|\\.innerHTML[[:space:]]*=|\\.outerHTML[[:space:]]*=|document\\.write\\(|insertAdjacentHTML\\(|verify[[:space:]]*=[[:space:]]*False|rejectUnauthorized[[:space:]]*:[[:space:]]*false|InsecureSkipVerify[[:space:]]*:[[:space:]]*true|Math\\.random\\(\'\n\n# Note: yaml.load matches both safe_load-adjacent and bare load; the regex avoids matching\n# yaml.safe_load by requiring an open paren directly after "load". Reviewers should confirm\n# whether a SafeLoader is passed.\n\nif [ -s "$TMP_JSON" ]; then\n  COUNT=$(wc -l < "$TMP_JSON" | tr -d \' \')\n  JSON_SINKS=$(tr \'\\n\' \',\' < "$TMP_JSON" | sed \'s/,$//\')\nelse\n  COUNT=0\n  JSON_SINKS=""\nfi\n\necho "## JSON"\necho \'```json\'\necho "{\\"sinks\\":[$JSON_SINKS],\\"count\\":$COUNT}"\necho \'```\'\necho ""\necho "> Reminder: these sinks are leads, not verdicts. Trace each to its input source and confirm"\necho "> reachability before classifying it as a vulnerability. Defensive review only."\n\nexit 0\n',
